import parmed as pmd
complex_top = pmd.load_file('./output/md/complex_with_lig.prmtop')
# Find LIG residue
for res in complex_top.residues:
    if res.name == 'LIG':
        print(f'Found LIG: idx={res.idx}, atoms={len(res.atoms)}')
        break
# Count residues
resnames = {}
for res in complex_top.residues:
    resnames[res.name] = resnames.get(res.name, 0) + 1
print('Residue counts:', resnames)
print(f'Total atoms: {len(complex_top.atoms)}')
" 2>&1"}
